import{_ as t,o as a,c as i,ag as s}from"./chunks/framework.Culc7SYV.js";const m=JSON.parse('{"title":"Custom Delimiters","description":"","frontmatter":{},"headers":[],"relativePath":"Custom-Delimiters.md","filePath":"Custom-Delimiters.md","lastUpdated":1772690052000}'),n={name:"Custom-Delimiters.md"};function o(l,e,r,d,c,p){return a(),i("div",null,[...e[0]||(e[0]=[s(`<h1 id="custom-delimiters" tabindex="-1">Custom Delimiters <a class="header-anchor" href="#custom-delimiters" aria-label="Permalink to &quot;Custom Delimiters&quot;">​</a></h1><p>Last modified: 17/03/2026</p><h2 id="purpose" tabindex="-1">Purpose <a class="header-anchor" href="#purpose" aria-label="Permalink to &quot;Purpose&quot;">​</a></h2><p>LearnKit uses <code>|</code> as the default card-field delimiter. If that conflicts with your note content (for example, heavy LaTeX), you can choose another delimiter.</p><h2 id="delimiter-list" tabindex="-1">Delimiter List <a class="header-anchor" href="#delimiter-list" aria-label="Permalink to &quot;Delimiter List&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Option</th><th>Character</th></tr></thead><tbody><tr><td>Pipe (default)</td><td><code>|</code></td></tr><tr><td>At sign</td><td><code>@</code></td></tr><tr><td>Tilde</td><td><code>~</code></td></tr><tr><td>Semicolon</td><td><code>;</code></td></tr></tbody></table><h2 id="change-steps" tabindex="-1">Change Steps <a class="header-anchor" href="#change-steps" aria-label="Permalink to &quot;Change Steps&quot;">​</a></h2><ol><li>Go to <strong>Settings -&gt; Storage -&gt; Card delimiter</strong>.</li><li>Select your preferred delimiter from the dropdown.</li></ol><h2 id="example" tabindex="-1">Example <a class="header-anchor" href="#example" aria-label="Permalink to &quot;Example&quot;">​</a></h2><p>With the <code>@</code> delimiter:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T @ Title @</span></span>
<span class="line"><span>Q @ What is the capital of France? @</span></span>
<span class="line"><span>A @ Paris @</span></span>
<span class="line"><span>I @ Located on the River Seine @</span></span>
<span class="line"><span>G @ Geography @</span></span></code></pre></div><p>With the <code>~</code> delimiter:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>T ~ Title ~</span></span>
<span class="line"><span>Q ~ What is the capital of France? ~</span></span>
<span class="line"><span>A ~ Paris ~</span></span></code></pre></div><h2 id="important-limit" tabindex="-1">Important Limit <a class="header-anchor" href="#important-limit" aria-label="Permalink to &quot;Important Limit&quot;">​</a></h2><div class="warning custom-block github-alert"><p class="custom-block-title">WARNING</p><p>Changing the delimiter does not migrate existing cards. Cards written with the old delimiter stop parsing. On the next sync, those cards can lose scheduling linkage/progress.</p></div><p>Only change this on a fresh vault, or after manually converting all existing cards.</p><h2 id="when-to-change" tabindex="-1">When to Change <a class="header-anchor" href="#when-to-change" aria-label="Permalink to &quot;When to Change&quot;">​</a></h2><p>Most users should keep <code>|</code>. Consider changing only when needed:</p><ul><li>Your notes use many <code>|</code> characters in content (for example LaTeX).</li><li>Another workflow or plugin conflicts with pipe-delimited fields.</li></ul><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p>Before changing globally, try the multi-line pattern in <a href="./Card-Formatting">Card Formatting</a>. That often avoids delimiter conflicts without breaking existing cards.</p></div>`,20)])])}const u=t(n,[["render",o]]);export{m as __pageData,u as default};
